INSERT INTO formations (id_formation, titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) SELECT gen_random_uuid(), v.* FROM (VALUES ('ISDA Community Management', 'Formation sur le community management selon les standards ISDA pour développer et gérer efficacement une communauté en ligne.', 5, 150000.00, 'entreprise', '2026-04-10', 30, '2026-01-14 12:37:32', '2026-02-18 23:44:04', NULL, E'--- OBJECTIFS ---\n• Comprendre les fondamentaux du community management\n• Maîtriser les outils et techniques de gestion de communauté\n• Développer l’engagement et la fidélisation\n• Mettre en place une stratégie digitale adaptée\n• Optimiser la visibilité et la réputation en ligne\n\n--- OBJECTIFS DÉTAILLÉS ---\nInitier les participants au community management selon ISDA, leur apprendre à gérer une communauté en ligne, développer l’engagement et mettre en place une stratégie digitale efficace.\n\n--- PRÉREQUIS ---\nConnaissances de base en marketing digital ou réseaux sociaux.\n\n--- CONTENU ---\nModule 1 : Introduction au community management ISDA\nModule 2 : Outils et plateformes de gestion\nModule 3 : Stratégies de contenu et engagement\nModule 4 : Gestion des interactions et modération\nModule 5 : Analyse et reporting\nModule 6 : Atelier pratique – Élaboration d’une stratégie de community management\n\n--- NIVEAU ---\nTous niveaux\n\n--- PUBLIC ---\nCommunity managers, responsables marketing digital, créateurs de contenu et entrepreneurs.\n\n--- MÉTHODES ---\nCours interactifs, démonstrations, ateliers pratiques, études de cas et simulations.\n\n--- SUPPORTS ---\nOutils de community management (Hootsuite, Buffer, Meta Business Suite), modèles de plan de contenu, supports PDF et slides.\n\n--- CERTIFICATION ---\nAttestation de participation remise par ISD Groupe', 'ba52f30c-c061-41b8-b0f7-afa6eca6fa76')) AS v(titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) WHERE NOT EXISTS (SELECT 1 FROM formations f WHERE f.titre = v.titre AND f.date_debut = v.date_debut::date);
